mapper.insert:
INSERT INTO schdl_info (
    CO_ID, SCHDL_SE_CD, SCHDL_NM, BGNG_DT, END_DT, ALL_DAY_YN,
    PLACE_NM, SCHDL_CN, USE_YN, REG_DT, RGTR_ID
) VALUES (
    #{coId}, #{schdlSeCd}, #{schdlNm}, #{bgngDt}, #{endDt}, IFNULL(#{allDayYn}, 'N'),
    #{placeNm}, #{schdlCn}, 'Y', NOW(), #{rgtrId}
)

INSERT INTO schdl_user_rel (SCHDL_SN, USER_ID, REG_DT)
SELECT #{schdlSn}, U.USER_ID, NOW()
FROM user_info U
WHERE U.USER_ID = #{targetUserId}
  AND U.CO_ID = #{coId}
  AND U.USE_YN = 'Y'

mapper.update:
UPDATE schdl_info
SET USE_YN = 'N',
    MDFCN_DT = NOW(),
    MDFR_ID = #{mdfrId}
WHERE SCHDL_SN = #{schdlSn}
  AND CO_ID = #{coId}
  AND USE_YN = 'Y'

mapper.select:
SELECT COUNT(1)
FROM schdl_info S
JOIN schdl_user_rel R ON R.SCHDL_SN = S.SCHDL_SN
WHERE S.CO_ID = #{coId}
  AND S.USE_YN = 'Y'
  AND R.USER_ID = #{targetUserId}

  AND S.SCHDL_SN <> #{schdlSn}

  AND S.BGNG_DT < STR_TO_DATE(#{endDt}, '%Y-%m-%d %H:%i')
  AND S.END_DT > STR_TO_DATE(#{bgngDt}, '%Y-%m-%d %H:%i')
